"use strict";(self.webpackChunkbereginia=self.webpackChunkbereginia||[]).push([[234],{8676:(e,t,n)=>{n.d(t,{Z:()=>d});var a=n(168),s=(n(3948),n(7294)),i=n(9124),l=n(5989),r=n(7723);const c={buttons:"Slider__buttons--aal",prevButton:"Slider__prevButton--qew",nextButton:"Slider__nextButton--S3t",content:"Slider__content--skQ"};var m;const o=(0,i.iv)(m||(m=(0,a.Z)(["\n  .slide-enter,\n  .slide-appear {\n    opacity: 0;\n    transform: translateX(5%);\n  }\n  .slide-enter-active,\n  .slide-appear-active {\n    opacity: 1;\n    transform: translateX(0);\n    transition: opacity 500ms, transform 500ms;\n  }\n  .slide-exit {\n    opacity: 1;\n    transform: translateX(0);\n  }\n  .slide-exit-active {\n    opacity: 0;\n    transform: translateX(-5%);\n    transition: opacity 500ms, transform 500ms;\n  }\n"]))),d=e=>{let{reviews:t,children:n}=e;const[a,m]=(0,s.useState)(0);return s.createElement(s.Fragment,null,s.createElement(i.xB,{styles:o}),s.createElement("div",{className:c.wrapper},s.createElement("div",{className:c.buttons,hidden:t.length<=1},s.createElement("button",{onClick:()=>{m(a>0?a-1:a)},disabled:0===a,className:c.prevButton}),s.createElement("button",{onClick:()=>{m(a<t.length-1?a+1:a)},disabled:a===t.length-1,className:c.nextButton})),s.createElement(l.Z,null,s.createElement(r.Z,{key:t[a],timeout:500,classNames:"slide"},n[a]))))}},9234:(e,t,n)=>{n.r(t),n.d(t,{default:()=>r});var a=n(7294),s=n(5990),i=n(8676);const l=[{title:"Анна",desc:"Здравствуйте Ирина! Хочу вас поблагодарить за то, что вы есть!\nЯ к вам обратилась в разбитом состоянии, после операции по гинекологии. После консультации я прошла первый этап лечения и сказать, что я довольна это ничего не сказать, появилась бодрость, силы и энергия. Благодарю вас за подход и понимание, за поддержку не смотря на то, что мы находимся в другой стране."},{title:"Лиза",desc:"Отзыв благодарности!\nК Ирине обратилась с сильной аллергией неизвестного происхождения в виде проявлений красных пятен по лицу и телу, которая не прошла даже после медикаментозного лечения. После консультации был назначен курс на месяц. Примерно через неделю от начала курса аллергия начала проходить и через две недели ее уже не было, вся кожа очистилась полностью. С тех пор чувствую себя хорошо, проблем с аллергией больше не нет. Безусловно привлекает такой подход, так как лечение исключительно натуральное (без медикаментов). Благодарю 1000 раз и всем рекомендую!"},{title:"Олег",desc:"Здравствуйте! Обратился к Ирине с проблемой желудка, много лет назад была язва и сейчас начал снова беспокоить желудок. Утром съедаю 2 ложки каши и сразу тяжесть как камень упал, ложился на пару минут, проходила отрыжка и продолжал ещё немного кушать. Частые боли в животе скручивали как бублик, иногда прям горело все внутри. После зимнего обследования и лечения медикаментами ничего толко не поменялось. \nПотом обратился к Ирине, прошел курс лечения, который она рекомендовала, лечение было без медикаментов, на основе трав и экстрактов. Сейчас кушаю все подряд, аппетит улучшился, тяжести нет, которая была, очень редко бывает дискомфорт, но я себе позволяю баночку пиво выпить. Также начал немного поправляться! Спасибо огромное!"},{title:"Валентин",desc:"Здравствуйте! Беспокоили меня панические атаки непонятного происхождения, на теле любой ветерок ощущался и создавал дискомфорт, любой мелкий сквозняк приводил к воспалению в мышцах спины, сильная нервозность. После обследований, консультации и прописанного курса, приступил к лечению, была назначена диета, пытался ее соблюдать, принимал препараты четко по прописанному курсу , сначала было ощущение что все зря и даже симптомы не уходили, где-то месяц ещё чувствовал себя без изменений, а потом под конец второго месяца уже начал забывать про свои проблемы. После трёх месяцев сдал повторный курс анализов, показатели улучшились и состояние тоже. Конечно есть ещё над чем работать, буду дальше продолжать новый курс, восстанавливать свои дефициты и налаживать качество жизни. Как итог после первого курса, я получил нового себя, теперь слежу за тем что я ем, обращаю внимание на своё самочувствие и стремлюсь быть здоровым.\nХочу выразить огромную благодарность Ирине, за качество знаний, за отдачу своей работе, даже в трудные времена получал ответы на свои вопросы, хоть это уже и не входило в оплаченную мною консультацию.\nСпасибо Вам!!!"},{title:"Ольга",desc:'Хочу написать отзыв благодарности Ивану и Ирине! 6 лет как мы периодически обращаемся в "Берегиню" и почти не ходим по врачам. \nЛечили: аденоиды 3-й степени у ребёнка, проходили антипаразитарные программы деткам (ребёнок после курса набрал 4 кг, был дефицит веса, восполнили дефициты витаминов и минералов, волосы начали расти, кожа перестала быть сухой).\nВысыпания на теле у взрослого были (после анализов, Ирина назначила курс на 2 месяца. Результат просто чудо - кожа очистилась.\nБлагодарю Вас за отзывчивость, в любое время можно написать и тебе ответят, посоветуют, помогут. Желаем процветания и успехов!!!\nОоочень рады что Вы есть!!!'},{title:"Катерина",desc:"Ирочка,добрый день! Хочу оставить отзыв))  Ты знаешь, когда шла на консультацию к тебе, понимала, что очень-очень мне интересно такой метод. И вообще все, что касается нетрадиционной медицины для меня это очень всегда было интересно. И когда я шла на консультацию, мне смущала сумма на  анализы и консультацию. И хотя сейчас я еще жду препараты, ещё не начала их прием, я уже применяю рекомендаций, которые ты мне дала. Я тебе хочу сказать, что  безумно тебе благодарна.  \nЯ себя вообще совершенно по-другому чувствую!\nВсю ту работу, которую ты выполнила для подготовки к  консультации- это огромный труд!!! Я хочу тебе сказать БЛАГОДАРЮ!!!Осознаю, что это абсолютно не  большая стоимость за консультацию!!! \n Вообще, благодарна тебе и всем рекомендую!!!"},{title:"Виктория",desc:"Здравствуйте Ирина 🤗 увидела тему про подготовку к детям))) и хочу вас поблагодарить от всего сердца 💕 у меня был непростой путь от операции в 2020г (по удалению миомы) я прошла курс детокса и ещё программу 4R и закрыла дефициты свои))) и что я хочу сказать мне 40 лет и я забеременела с первого раза))🙏хотя меня убеждали что без Эко не получится и без гормонов. \n\nЭто две большие разницы между первой беременностью и сейчас, без токсикоза, без отёков и т.д. И Слава Богу все анализы в порядке на всевозможные отклонения 🙏 я хотела написать вам отзыв когда рожу, но увидела тему которую вы затронули и подумала, что кому-то мой отзыв поможет решиться обратиться к вам . Благодарю вас за всё 🤗🙏💐"}],r=()=>a.createElement("section",{className:"Reviews__container--NMf",id:"reviews"},a.createElement("h4",{className:"Reviews__title--hdz"},"Наши отзывы"),a.createElement("div",{className:"Reviews__content--wPV"},a.createElement("div",{className:"Reviews__descContainer--mY6"},a.createElement("p",{className:"Reviews__desc--TLa"},"Более 1000 человек восстановили свое здоровье и улучшили качество жизни после консультации с Ириной")),a.createElement(i.Z,{reviews:l},l.map((e=>{let{title:t,desc:n}=e;return a.createElement("div",{key:t,className:"Reviews__reviewContainer--Hc0"},a.createElement(s.Q,{src:"../../../../images/irina/quotes.svg"}),a.createElement("h6",{className:"Reviews__reviewTitle--T5B"},t),a.createElement("p",{className:"Reviews__reviewDesc--H6I"},n))})))))}}]);